import React, { useState } from "react";

export default function PinScreen({ onConfirm, onCancel }) {
  const [input, setInput] = useState("");

  return (
    <div className="min-h-screen bg-gray-50 px-6 pt-20">
      <h2 className="text-xl font-bold mb-6 text-center">
        Enter PIN
      </h2>

      <input
        type="password"
        maxLength={4}
        value={input}
        onChange={(e) => setInput(e.target.value)}
        className="w-full text-center text-2xl tracking-widest py-4 border rounded-xl"
      />

      <button
        onClick={() => onConfirm(input)}
        className="mt-6 w-full bg-emerald-600 text-white py-4 rounded-xl font-semibold"
      >
        Confirm
      </button>

      <button
        onClick={onCancel}
        className="mt-3 w-full text-gray-400"
      >
        Cancel
      </button>
    </div>
  );
}
